The central scheduler that selects the highest-priority ELIGIBLE job under current constraints. Replaces the v1 PreAnalysisScheduler FIFO approach which had a correctness bug: a paused T1 at the front of the queue blocked eligible T0 work behind it.

WHY ELIGIBILITY-AWARE: Simple FIFO with fetchActionableRecords().first returns if the first record is charging-only and the device is not charging, blocking all subsequent work. The scheduler must select from eligible work only.

TWO LOGICAL LANES:
- Immediate lane: T0 / explicit downloads / Up Next episodes. Always eligible (no charging requirement).
- Deferred lane: T1+ charging-only extension work. Eligible only when isCharging && !shouldThrottleAnalysis.

JOB SELECTION: Delegates to AnalysisStore.fetchNextEligibleJob() (defined in bd-25o). The SQL is inlined in that bead.

PREREQUISITE CONFIG (Playhead/Services/PreAnalysis/PreAnalysisConfig.swift):
  struct PreAnalysisConfig: Codable, Sendable {
      var isEnabled: Bool = true
      var defaultT0DepthSeconds: Double = 90
      var t1DepthSeconds: Double = 300
      var t2DepthSeconds: Double = 900
      private static let key = "PreAnalysisConfig"
      static func load() -> PreAnalysisConfig {
          guard let data = UserDefaults.standard.data(forKey: key),
                let config = try? JSONDecoder().decode(PreAnalysisConfig.self, from: data)
          else { return PreAnalysisConfig() }
          return config
      }
      func save() {
          if let data = try? JSONEncoder().encode(self) {
              UserDefaults.standard.set(data, forKey: key)
          }
      }
  }

SCHEDULER ACTOR (Playhead/Services/PreAnalysis/AnalysisWorkScheduler.swift):

  actor AnalysisWorkScheduler {
      private let store: AnalysisStore
      private let jobRunner: AnalysisJobRunner
      private let capabilitiesService: CapabilitiesService
      private let downloadManager: any DownloadProviding  // protocol from bd-1dl
      private let config: PreAnalysisConfig
      private let logger = Logger(subsystem: "com.playhead", category: "WorkScheduler")

      private var schedulerTask: Task<Void, Never>?
      private var shouldCancelCurrentJob = false

      init(store: AnalysisStore, jobRunner: AnalysisJobRunner, capabilitiesService: CapabilitiesService, downloadManager: any DownloadProviding, config: PreAnalysisConfig = .load())

      // MARK: - Public API

      func enqueue(episodeId: String, podcastId: String?, downloadId: String, sourceFingerprint: String, isExplicitDownload: Bool, desiredCoverage: Double?) async {
          let priority = isExplicitDownload ? 10 : 0
          let coverage = desiredCoverage ?? config.defaultT0DepthSeconds
          let workKey = AnalysisJob.computeWorkKey(fingerprint: sourceFingerprint, analysisVersion: kAnalysisVersion, jobType: "preAnalysis")
          let job = AnalysisJob(
              jobId: UUID().uuidString, jobType: "preAnalysis",
              episodeId: episodeId, podcastId: podcastId, analysisAssetId: nil,
              workKey: workKey, sourceFingerprint: sourceFingerprint, downloadId: downloadId,
              priority: priority, desiredCoverageSec: coverage,
              featureCoverageSec: 0, transcriptCoverageSec: 0, cueCoverageSec: 0,
              state: "queued", attemptCount: 0, nextEligibleAt: nil,
              leaseOwner: nil, leaseExpiresAt: nil, lastErrorCode: nil,
              createdAt: Date().timeIntervalSince1970, updatedAt: Date().timeIntervalSince1970
          )
          try? await store.insertJob(job)
          wakeSchedulerLoop()
      }

      func playbackStarted(episodeId: String) async {
          shouldCancelCurrentJob = true
          try? await Task.sleep(for: .seconds(3))
          if let jobs = try? await store.fetchJobsByState("running") {
              for job in jobs where job.episodeId == episodeId {
                  try? await store.releaseLease(jobId: job.jobId)
              }
          }
      }

      func episodeDeleted(episodeId: String) async {
          if let jobs = try? await store.fetchJobsByState("queued") {
              for job in jobs where job.episodeId == episodeId {
                  try? await store.updateJobState(jobId: job.jobId, state: "superseded")
              }
          }
      }

      func cancelCurrentJob() { shouldCancelCurrentJob = true }

      /// Start the scheduler loop. Call after reconciliation is complete.
      func startSchedulerLoop() {
          schedulerTask?.cancel()
          schedulerTask = Task { [weak self] in
              guard let self else { return }
              while !Task.isCancelled {
                  guard await self.config.isEnabled else {
                      try? await Task.sleep(for: .seconds(30))
                      continue
                  }
                  let snapshot = await capabilitiesService.currentSnapshot
                  guard let job = try? await store.fetchNextEligibleJob(
                      isCharging: snapshot.isCharging,
                      isThermalOk: !snapshot.shouldThrottleAnalysis,
                      t0ThresholdSec: config.defaultT0DepthSeconds,
                      now: Date().timeIntervalSince1970
                  ) else {
                      try? await Task.sleep(for: .seconds(10))
                      continue
                  }
                  await processJob(job)
              }
          }
      }

      private func wakeSchedulerLoop() {
          schedulerTask?.cancel()
          startSchedulerLoop()
      }
  }

NOTE ON RECONCILIATION: The scheduler does NOT own reconciliation or version-checking. The composition root (bd-jzl) calls reconciler.reconcile() before scheduler.startSchedulerLoop(). This avoids a circular dependency between the scheduler and the reconciler.

AUDIO URL RESOLUTION: Before running a job, resolve downloadId -> file URL:
  guard let audioURL = downloadManager.cachedFileURL(for: job.downloadId) else {
      try await store.updateJobState(jobId: job.jobId, state: "blocked:missingFile")
      return
  }

T0 DEPTH POLICY: Default desiredCoverageSec for T0 is config.defaultT0DepthSeconds (default 90s). Explicit downloads and Up Next episodes get priority=10; auto-downloads get priority=0.

TIER ADVANCEMENT (in processJob, after runner returns):
  switch outcome.stopReason {
  case .reachedTarget where outcome.cueCoverageSec >= job.desiredCoverageSec:
      let nextTier = nextTierCoverage(current: job.desiredCoverageSec)
      if let nextCoverage = nextTier {
          let nextJob = AnalysisJob(... desiredCoverageSec: nextCoverage, state: "paused", ...)
          try await store.insertJob(nextJob)
      } else {
          try await store.updateJobState(jobId: job.jobId, state: "complete")
      }
  case .blockedByModel:
      try await store.updateJobState(jobId: job.jobId, state: "blocked:modelUnavailable", nextEligibleAt: Date().timeIntervalSince1970 + 300)
  case .pausedForThermal, .memoryPressure:
      try await store.updateJobState(jobId: job.jobId, state: "paused", nextEligibleAt: Date().timeIntervalSince1970 + 30)
  case .failed(let reason):
      let backoff = min(pow(2.0, Double(job.attemptCount + 1)) * 60, 3600)
      try await store.updateJobState(jobId: job.jobId, state: "failed", nextEligibleAt: Date().timeIntervalSince1970 + backoff, lastErrorCode: reason)
  case .backgroundExpired:
      try await store.updateJobState(jobId: job.jobId, state: "queued")
  default: break
  }

TIER DEFINITIONS:
  private func nextTierCoverage(current: Double) -> Double? {
      switch current {
      case ..<90:  return 90
      case ..<300: return 300   // T0 -> T1 (5min)
      case ..<900: return 900   // T1 -> T2 (15min)
      default:     return nil   // T2 complete
      }
  }

PREEMPTION: At tier boundaries, re-query fetchNextEligibleJob rather than blindly processing the tier-advancement job.

CONCURRENCY: One CPU-heavy job at a time. The scheduler loop is serial.

LEASE MANAGEMENT:
  Before running: try await store.acquireLease(jobId: job.jobId, owner: "preAnalysis", expiresAt: Date().timeIntervalSince1970 + 300)
  Periodically renew during long jobs: spawn background Task calling store.renewLease every 120s.
  On completion: try await store.releaseLease(jobId: job.jobId)

